/* CSS styles for the main.css file */

body {
  background-color: #f2f2f2;
  font-family: Arial, sans-serif;
}

h1 {
  color: #333;
  font-size: 24px;
}

p {
  color: #666;
  line-height: 1.5;
}

/* CSS styles for the reset.css file */

/* Reset default browser styles */

html, body, div, span,
h1, h2, h3, h4, h5, h6, p, img,
a, em, strong, sub, sup,
abbr, acronym, address, bdo,
del, dfn, ins, kbd, q, samp,
small, tt, var, dl, dt, dd, ol, ul, li,
fieldset, form, label, legend,
table, caption, tbody, tfoot, thead, tr, th, td {
  margin: 0;
  padding: 0;
  border: 0;
  outline: 0;
  font-size: 100%;
  vertical-align: baseline;
  background: transparent;
}

body {
  line-height: 1;
}

ol, ul {
  list-style: none;
}

blockquote, q {
  quotes: none;
}

blockquote:before, blockquote:after,
q:before, q:after {
  content: '';
  content: none;
}

table {
  border-collapse: collapse;
  border-spacing: 0;
}

/* JavaScript code for the main.js file */

// Example function
function greetUser(name) {
  console.log(`Hello, ${name}! Welcome to the website.`);
}

// Call the function
greetUser("John");

/* JavaScript code for the utils.js file */

// Utility functions

function add(a, b) {
  return a + b;
}

function subtract(a, b) {
  return a - b;
}

function multiply(a, b) {
  return a * b;
}

function divide(a, b) {
  return a / b;
}

/* JavaScript code for library1.js */

// Example library function 1
function greet(name) {
  console.log(`Hello, ${name}! Welcome to the website.`);
}

// Example library function 2
function calculateSquare(num) {
  return num * num;
}

// Exported functions
module.exports = {
  greet,
  calculateSquare
};

/* JavaScript code for library2.js */

// Example library function 1
function capitalize(string) {
  return string.charAt(0).toUpperCase() + string.slice(1);
}

// Example library function 2
function reverseArray(array) {
  return array.reverse();
}

// Exported functions
module.exports = {
  capitalize,
  reverseArray
};

/* JavaScript code for library3.js */

// Example library function 1
function generateRandomNumber(min, max) {
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

// Example library function 2
function formatCurrency(amount) {
  return "$" + amount.toFixed(2);
}

// Exported functions
module.exports = {
  generateRandomNumber,
  formatCurrency
};
